import React from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../hooks';
import { scrollToSection, COMPANY_INFO } from '../utils';
import { Button } from './ui';

const CTA = () => {
  const [ref, isVisible] = useScrollReveal();

  return (
    <section className="bg-gold py-20 md:py-32 relative overflow-hidden">
      {/* Decorative Circle */}
      <div className="absolute w-[300px] h-[300px] border border-primary/10 rounded-full -top-[100px] right-[10%] animate-slow-spin pointer-events-none" style={{ animationDirection: 'reverse' }} />

      <div className="container">
        <div
          ref={ref}
          className={clsx(
            'text-center max-w-[700px] mx-auto relative z-10 opacity-0 translate-y-10 transition-all duration-700 ease-out-expo',
            isVisible && 'opacity-100 translate-y-0'
          )}
        >
          <h2 className="text-display-lg font-medium text-primary mb-6">
            Protect What <span className="font-serif italic">Matters</span>
          </h2>
          <p className="text-xl text-primary/60 mb-4">
            For just ${COMPANY_INFO.price}/year, ensure your will is safe, accessible, and ready to honor your wishes.
          </p>
          <p className="text-base text-primary/40 mb-10">
            Opening promo — ${COMPANY_INFO.priceAfterPromo}/year after your first year
          </p>
          <div className="flex flex-wrap gap-4 justify-center">
            <Button
              href="#pricing"
              variant="dark"
              icon
              onClick={(e) => scrollToSection(e, 'pricing')}
            >
              Get Started for ${COMPANY_INFO.price}/yr
            </Button>
            <Button
              href="#contact"
              variant="outline-dark"
              onClick={(e) => scrollToSection(e, 'contact')}
            >
              Contact Us
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
};

export default CTA;
